/** Информация о доступности склада. */
export interface WarehouseAvailabilityStatus {
  /**
   * Причина недоступности склада:
   * - `UNSPECIFIED` — не определена;
   * - `NO_REASON` — нет причины;
   * - `PARTIAL_MATRIX_AVAILABLE` — склад не может принять часть товаров;
   * - `NOT_AVAILABLE_MATRIX` — склад не может принять все товары;
   * - `NOT_AVAILABLE_RANK` — склад недоступен из-за рейтинга;
   * - `NOT_AVAILABLE_ROUTE` — нет доступного маршрута;
   * - `NOT_AVAILABLE_TIMESLOT_FOR_DROP_OFF_POINT` — нет таймслотов на точке отгрузки;
   * - `NOT_AVAILABLE_TIMESLOT_FOR_STORAGE_WAREHOUSE` — нет таймслотов на складе поставки;
   * - `NOT_AVAILABLE_TIMESLOT_FOR_BOTH_WAREHOUSES` — нет таймслотов на складах отгрузки и поставки;
   * - `NOT_AVAILABLE_TIMESLOT_NO_REASON` — нет таймслотов.
   */
  invalid_reason?: AvailabilityStatusInvalidReasonEnum;
  /**
   * Статус доступности:
   * - `UNSPECIFIED` — не определён,
   * - `FULL_AVAILABLE` — доступен,
   * - `PARTIAL_AVAILABLE` — частично доступен,
   * - `NOT_AVAILABLE` — недоступен.
   */
  state?: AvailabilityStatusStateEnum;
}

/** Склад хранения для поставок с типом `DIRECT`. */
export interface WarehouseStorageWarehouse {
  /** Адрес склада хранения. */
  address?: string;
  /** Название склада хранения. */
  name?: string;
  /**
   * Идентификатор склада хранения.
   * @format int64
   */
  warehouse_id?: number;
}

export interface ClusterWarehouse {
  /** Информация о доступности склада. */
  availability_status?: WarehouseAvailabilityStatus;
  /** Идентификатор товарного состава. */
  bundle_id?: string;
  /** Комплект товаров, которые не попадают в поставку. Используйте значение параметра в методе [/v1/supply-order/bundle](#operation/SupplyOrderBundle), чтобы получить подробную информацию. */
  restricted_bundle_id?: string;
  /** Склад хранения для поставок с типом `DIRECT`. */
  storage_warehouse?: WarehouseStorageWarehouse;
  /**
   * Метки товаров в заявке на поставку:
   *  - `UNSPECIFIED` — не определена;
   *  - `TRACEABLE` — товар с признаком прослеживаемости;
   *  - `ETTN_REQUIRED` — товар, для которого необходима электронная ТТН;
   *  - `EVSD_REQUIRED` — товар с сертификацией «Меркурий»;
   *  - `MARKING_REQUIRED` — товар с обязательной маркировкой «Честный ЗНАК»;
   *  - `MARKING_POSSIBLE` — товар с возможной маркировкой «Честный ЗНАК»;
   *  - `JEWELRY` — товар с признаком ювелирного изделия;
   *  - `FREEZE_STOCK_FOR_MARKING_AFTER_ACCEPTANCE` — заморозка стока для поставок, в которых есть маркируемые товары и не был передан УПД;
   *  - `UTD_REQUIRED` — товар с обязательным УПД;
   *  - `UNDEFINED` — неизвестная.
   */
  supply_tags?: WarehouseSupplyTagEnum[];
  /**
   * Ранг склада в кластере. Только для поставок с типом `DIRECT`.
   * @format int32
   */
  total_rank?: number;
  /**
   * Рейтинг склада.
   * @format double
   */
  total_score?: number;
}

