/** Тип сертификата. Чтобы получить доступные типы, используйте метод [GET /v1/product/certificate/types](#operation/ProductAPI_ProductCertificateTypes). */
export enum ProductApiProductCertificateCreateTypeCodeEnum {
  CertificateOfConformity = "certificate_of_conformity",
  Declaration = "declaration",
  CertificateOfRegistration = "certificate_of_registration",
  RegistrationCertificate = "registration_certificate",
  RefusedLetter = "refused_letter",
  VeterinaryCoverDocument = "veterinary_cover_document",
  SafetyDataSheet = "safety_data_sheet",
}

/** Тип соответствия требованиям. Чтобы получить доступные типы, используйте метод [GET /v1/product/certificate/accordance-types](#operation/ProductAPI_ProductCertificateAccordanceTypes). Параметр обязательный, если `type_code = declaration`, `certificate_of_conformity` или `safety_data_sheet`. */
export enum ProductApiProductCertificateCreateAccordanceTypeCodeEnum {
  TechnicalRegulationsRf = "technical_regulations_rf",
  TechnicalRegulationsCu = "technical_regulations_cu",
  Gost = "gost",
}

export interface ProductApiProductCertificateCreatePayload {
  /** Массив сертификатов для товара. Допустимые расширения jpg, jpeg, png, pdf. */
  files: File[];
  /** Название сертификата. Максимум 100 символов. */
  name: string;
  /** Номер сертификата. Максимум 100 символов. */
  number: string;
  /** Тип сертификата. Чтобы получить доступные типы, используйте метод [GET /v1/product/certificate/types](#operation/ProductAPI_ProductCertificateTypes). */
  type_code: ProductApiProductCertificateCreateTypeCodeEnum;
  /** Тип соответствия требованиям. Чтобы получить доступные типы, используйте метод [GET /v1/product/certificate/accordance-types](#operation/ProductAPI_ProductCertificateAccordanceTypes). Параметр обязательный, если `type_code = declaration`, `certificate_of_conformity` или `safety_data_sheet`. */
  accordance_type_code?: ProductApiProductCertificateCreateAccordanceTypeCodeEnum;
  /**
   * Дата начала действия сертификата.
   * @format date-time
   * @default "2021-04-30T11:31:26Z"
   */
  issue_date: string;
  /**
   * Дата окончания действия сертификата. Может быть пустым для бессрочных сертификатов.
   *
   * Формат: `2021-04-30T11:31:26Z`.
   * @format date-time
   */
  expire_date?: string;
}

